   206→export const useKanbanStore = create<KanbanStore>()(
   207→  persist(
   208→    (set, get) => ({
   209→      // Initial state
   210→      tasks: [],
   211→      columns: DEFAULT_COLUMNS,
   212→      dependencies: [], // Phase 5: Task dependencies
   213→      archivedTasks: [], // Phase A: Archived tasks
   214→      nextCardNumber: 1, // Phase A: Auto-incrementing card number counter
   215→      visibleColumns: 5, // UI: Number of columns visible before scrolling (default: 5)
   216→      undoHistory: [], // Undo system: stores last 5 actions
   217→      baseline: null, // Phase 1.4: Project baseline snapshot
   218→
   219→      // ==================== TASK ACTIONS ====================
   220→
   221→      addTask: (taskData) => {
   222→        const currentNumber = get().nextCardNumber || 1;
   223→
   224→        const newTask: Task = {
   225→          ...taskData,
   226→          id: Date.now().toString(),
   227→          created: new Date().toISOString(),
   228→          cardNumber: currentNumber, // Phase A: Assign auto-incrementing card number
   229→          checklist: [],
   230→          comments: [],
   231→          activityLog: [],
   232→        };
   233→
   234→        set((state) => ({
   235→          tasks: [...state.tasks, newTask],
   236→          nextCardNumber: currentNumber + 1, // Increment counter
   237→        }));
   238→
   239→        // Log creation
   240→        get().logActivity(newTask.id, {
   241→          action: 'created',
   242→        });
   243→
   244→        // P1: Trigger automation rules for 'task.created'
   245→        setTimeout(async () => {
   246→          const { useAutomationStore } = await import('./useAutomationStore');
   247→          const automationStore = useAutomationStore.getState();
   248→          const context: AutomationContext = {
   249→            taskId: newTask.id,
   250→            timestamp: new Date().toISOString(),
   251→          };
   252→
   253→          const logs = await evaluateRules(
   254→            automationStore.rules,
   255→            'task.created',
   256→            newTask,
   257→            context,
   258→            get()
   259→          );
   260→          logs.forEach((log) => automationStore.addExecutionLog(log));
   261→        }, 0);
   262→      },
   263→
   264→      updateTask: (id, updates) => {
   265→        const oldTask = get().tasks.find((t) => t.id === id);
   266→        if (!oldTask) return;
   267→
   268→        // Phase 1.2: Check if date changes trigger dependent shifts
   269→        // Note: This only updates the primary task. Components must call
   270→        // calculateDependentShifts separately and show confirmation dialog
   271→        // before calling applyDependentShifts.
   272→
   273→        set((state) => ({
   274→          tasks: state.tasks.map((task) =>
   275→            task.id === id ? { ...task, ...updates } : task
   276→          ),
   277→        }));
   278→
   279→        // Log updates (track specific fields)
   280→        Object.keys(updates).forEach((field) => {
   281→          if (field !== 'activityLog') { // Don't log the log itself
   282→            get().logActivity(id, {
   283→              action: 'updated',
   284→              field,
   285→              oldValue: String(oldTask[field as keyof Task] ?? ''),
   286→              newValue: String(updates[field as keyof Task] ?? ''),
   287→            });
   288→          }
   289→        });
   290→      },
   291→
   292→      deleteTask: (id) =>
   293→        set((state) => ({
   294→          tasks: state.tasks.filter((task) => task.id !== id),
   295→        })),
   296→
   297→      moveTask: (id, newStatus) => {
   298→        const oldTask = get().tasks.find((t) => t.id === id);
   299→        if (!oldTask) return;
   300→
   301→        // PHASE 5 PART 6: Validate dependencies before moving to "done"
   302→        if (newStatus === 'done') {
   303→          const blockers = get().getBlockers(id);
   304→          const incompleteBlockers = blockers.filter((b) => b.status !== 'done');
   305→
   306→          if (incompleteBlockers.length > 0) {
   307→            log.warn('Cannot complete task: blocked by incomplete tasks', {
   308→              taskId: id,
   309→              taskTitle: oldTask.title,
   310→              blockerCount: incompleteBlockers.length
   311→            });
   312→            // TODO: Show toast notification in UI
   313→            return; // Prevent move
   314→          }
   315→        }
   316→
   317→        // PHASE A: Track when task is completed (for auto-archive)
   318→        const updates: Partial<Task> = { status: newStatus };
   319→        if (newStatus === 'done' && oldTask.status !== 'done') {
   320→          updates.lastCompletedAt = new Date().toISOString();
   321→        }
   322→
   323→        // P1: AUTO-GENERATE NEXT RECURRING INSTANCE
   324→        // If completing a recurring task instance, generate next occurrence
   325→        const isCompletingRecurringInstance = newStatus === 'done' && oldTask.recurrenceId;
   326→
   327→        set((state) => ({
   328→          tasks: state.tasks.map((task) =>
   329→            task.id === id ? { ...task, ...updates } : task
   330→          ),
   331→        }));
   332→
   333→        // Generate next instance after state update (avoid mutation during update)
   334→        if (isCompletingRecurringInstance) {
   335→          setTimeout(() => {
   336→            // Pass the completed task instance for recurFromCompletion calculation
   337→            const completedTask = get().tasks.find((t) => t.id === id);
   338→            get().generateNextRecurringInstance(oldTask.recurrenceId!, completedTask);
   339→          }, 0);
   340→        }
   341→
   342→        // Log move
   343→        get().logActivity(id, {
   344→          action: 'moved',
   345→          field: 'status',
   346→          oldValue: oldTask.status,
   347→          newValue: newStatus,
   348→        });
   349→
   350→        // P1: Trigger automation rules for 'task.moved' and potentially 'task.completed'
   351→        setTimeout(async () => {
   352→          const { useAutomationStore } = await import('./useAutomationStore');
   353→          const automationStore = useAutomationStore.getState();
   354→          const updatedTask = get().tasks.find((t) => t.id === id);
   355→          if (!updatedTask) return;
   356→
   357→          const context: AutomationContext = {
   358→            taskId: id,
   359→            previousStatus: oldTask.status,
   360→            newStatus,
   361→            timestamp: new Date().toISOString(),
   362→          };
   363→
   364→          // Trigger 'task.moved' for all status changes
   365→          const movedLogs = await evaluateRules(
   366→            automationStore.rules,
   367→            'task.moved',
   368→            updatedTask,
   369→            context,
   370→            get()
   371→          );
   372→          movedLogs.forEach((log) => automationStore.addExecutionLog(log));
   373→
   374→          // Also trigger 'task.completed' if moved to done
   375→          if (newStatus === 'done') {
   376→            const completedLogs = await evaluateRules(
   377→              automationStore.rules,
   378→              'task.completed',
   379→              updatedTask,
   380→              context,
   381→              get()
   382→            );
   383→            completedLogs.forEach((log) => automationStore.addExecutionLog(log));
   384→          }
   385→        }, 0);
   386→      },
   387→
   388→      getTasksByStatus: (status) => {
   389→        return get().tasks.filter((task) => task.status === status);
   390→      },
   391→
   392→      // ==================== RECURRING TASK ACTIONS (P1) ====================
   393→
   394→      setTaskRecurrence: (taskId, recurrence) => {
   395→        const task = get().tasks.find((t) => t.id === taskId);
   396→        if (!task) {
   397→          log.warn('Task not found for recurrence', { taskId });
   398→          return;
   399→        }
   400→
   401→        // Mark as recurring parent and calculate next occurrence
   402→        const updates: Partial<Task> = {
   403→          recurrence,
   404→          isRecurringParent: recurrence ? true : undefined,
   405→          nextOccurrence: recurrence ? updateNextOccurrence({ ...task, recurrence }) : undefined,
   406→        };
   407→
   408→        get().updateTask(taskId, updates);
   409→
   410→        log.info('Task recurrence set', { taskId, frequency: recurrence?.frequency });
   411→      },
   412→
   413→      generateNextRecurringInstance: (parentTaskId, lastCompletedInstance) => {
   414→        const parentTask = get().tasks.find((t) => t.id === parentTaskId);
   415→        if (!parentTask || !parentTask.isRecurringParent) {
   416→          log.warn('Not a recurring parent task', { parentTaskId });
   417→          return;
   418→        }
   419→
   420→        // Check if we should generate next instance
   421→        if (!shouldGenerateNextInstance(parentTask, get().tasks)) {
   422→          log.debug('Next instance not needed yet', { parentTaskId });
   423→          return;
   424→        }
   425→
   426→        // Generate new instance (pass completed instance for recurFromCompletion)
   427→        const instance = generateNextInstance(parentTask, lastCompletedInstance);
   428→        if (!instance) {
   429→          log.debug('No more instances to generate (series ended)', { parentTaskId });
   430→          return;
   431→        }
   432→
   433→        // Add instance to tasks
   434→        set((state) => ({
   435→          tasks: [...state.tasks, instance],
   436→        }));
   437→
   438→        // Update parent's nextOccurrence
   439→        const nextOccurrence = updateNextOccurrence(parentTask);
   440→        get().updateTask(parentTaskId, { nextOccurrence });
   441→
   442→        log.info('Generated recurring task instance', {
   443→          parentId: parentTaskId,
   444→          instanceId: instance.id,
   445→          dueDate: instance.dueDate,
   446→        });
   447→      },
   448→
   449→      getRecurringTaskInstances: (parentTaskId) => {
   450→        return getTaskInstances(
   451→          get().tasks.find((t) => t.id === parentTaskId)!,
   452→          get().tasks
   453→        );
   454→      },
   455→
   456→      // ==================== COLUMN ACTIONS ====================
   457→
   458→      addColumn: (columnData) => {
   459→        const columns = get().columns;
   460→        const newColumn: KanbanColumn = {
   461→          ...columnData,
   462→          id: `col-${Date.now()}`,
   463→          order: columns.length,
   464→        };
   465→
   466→        set((state) => ({
   467→          columns: [...state.columns, newColumn],
   468→        }));
   469→      },
   470→
   471→      updateColumn: (id, updates) => {
   472→        set((state) => ({
   473→          columns: state.columns.map((col) =>
   474→            col.id === id ? { ...col, ...updates } : col
   475→          ),
   476→        }));
   477→      },
   478→
   479→      deleteColumn: (id) => {
   480→        const state = get();
   481→        const columnToDelete = state.columns.find(col => col.id === id);
   482→
   483→        if (!columnToDelete) {
   484→          log.warn('Column not found for deletion', { columnId: id });
   485→          return;
   486→        }
   487→
   488→        // Save undo entry BEFORE making changes
   489→        get().addToUndoHistory({
   490→          action: 'deleteColumn',
   491→          description: `Deleted column '${columnToDelete.title}'`,
   492→          previousState: {
   493→            columns: state.columns,
   494→            tasks: state.tasks,
   495→          },
   496→        });
   497→
   498→        // Find first remaining column (fallback, not hardcoded 'backlog')
   499→        const firstRemainingColumn = state.columns.find(col => col.id !== id);
   500→
   501→        if (!firstRemainingColumn) {
   502→          log.error('Cannot delete last column');
   503→          return;
   504→        }
   505→
   506→        // Move all tasks from deleted column to first remaining column
   507→        set((state) => ({
   508→          columns: state.columns.filter((col) => col.id !== id),
   509→          tasks: state.tasks.map((task) =>
   510→            task.status === id as TaskStatus
   511→              ? { ...task, status: firstRemainingColumn.id as TaskStatus }
   512→              : task
   513→          ),
   514→        }));
   515→      },
   516→
   517→      reorderColumns: (columnIds) => {
   518→        const columns = get().columns;
   519→        const reordered = columnIds
   520→          .map((id) => columns.find((col) => col.id === id))
   521→          .filter((col): col is KanbanColumn => col !== undefined)
   522→          .map((col, index) => ({ ...col, order: index }));
   523→
   524→        set({ columns: reordered });
   525→      },
   526→
   527→      replaceAllColumns: (newColumns: Omit<KanbanColumn, 'id' | 'order'>[]) => {
   528→        const state = get();
   529→
   530→        // Save undo entry BEFORE making changes
   531→        get().addToUndoHistory({
   532→          action: 'replaceAllColumns',
   533→          description: `Applied template`,
   534→          previousState: {
   535→            columns: state.columns,
   536→            tasks: state.tasks,
   537→          },
