  1182→      removeDependency: (taskId, dependencyId) => {
  1183→        const task = get().tasks.find(t => t.id === taskId);
  1184→        if (!task || !task.dependencies) {
  1185→          log.warn('Task or dependencies not found', { taskId });
  1186→          return;
  1187→        }
  1188→
  1189→        const dependency = task.dependencies.find(d => d.taskId === dependencyId);
  1190→        if (!dependency) {
  1191→          log.warn('Dependency not found', { taskId, dependencyId });
  1192→          return;
  1193→        }
  1194→
  1195→        // Remove dependency from task
  1196→        set((state) => ({
  1197→          tasks: state.tasks.map(t => {
  1198→            if (t.id === taskId) {
  1199→              return {
  1200→                ...t,
  1201→                dependencies: (t.dependencies || []).filter(d => d.taskId !== dependencyId),
  1202→              };
  1203→            }
  1204→            return t;
  1205→          }),
  1206→        }));
  1207→
  1208→        // Log activity
  1209→        const dependencyLabel = {
  1210→          'finish-to-start': 'FS',
  1211→          'start-to-start': 'SS',
  1212→          'finish-to-finish': 'FF',
  1213→          'start-to-finish': 'SF',
  1214→        }[dependency.type];
  1215→
  1216→        get().logActivity(taskId, {
  1217→          action: 'updated',
  1218→          field: 'dependency',
  1219→          oldValue: `Depended on task ${dependencyId} (${dependencyLabel})`,
  1220→        });
  1221→      },
  1222→
  1223→      getBlockers: (taskId) => {
  1224→        // Get tasks that this task depends on (blockers)
  1225→        const task = get().tasks.find(t => t.id === taskId);
  1226→        if (!task || !task.dependencies) return [];
  1227→
  1228→        const blockerIds = task.dependencies.map(d => d.taskId);
  1229→        return get().tasks.filter(t => blockerIds.includes(t.id));
  1230→      },
  1231→
  1232→      getBlocked: (taskId) => {
  1233→        // Get tasks that depend on this task (blocked by this task)
  1234→        const allTasks = get().tasks;
  1235→        return allTasks.filter(t =>
  1236→          t.dependencies?.some(d => d.taskId === taskId)
  1237→        );
  1238→      },
  1239→
  1240→      getOverdueBlockers: (taskId) => {
  1241→        // P1: Get blocker tasks that are overdue (for dependency warnings)
  1242→        const blockers = get().getBlockers(taskId);
  1243→        const today = new Date();
  1244→        today.setHours(0, 0, 0, 0); // Start of day
  1245→
  1246→        return blockers.filter(blocker => {
  1247→          // Blocker is overdue if:
  1248→          // 1. It's not done
  1249→          // 2. It has a due date
  1250→          // 3. Due date is before today
  1251→          if (blocker.status === 'done') return false;
  1252→          if (!blocker.dueDate) return false;
  1253→
  1254→          const dueDate = new Date(blocker.dueDate);
  1255→          dueDate.setHours(0, 0, 0, 0);
  1256→
  1257→          return dueDate < today;
  1258→        });
  1259→      },
  1260→
  1261→      // ==================== PHASE 1.2: AUTO-SHIFT DEPENDENT TASKS ====================
  1262→
  1263→      applyDependentShifts: (shifts) => {
  1264→        if (shifts.length === 0) return;
  1265→
  1266→        log.info(`Applying ${shifts.length} dependent task shifts`);
  1267→
  1268→        set((state) => ({
  1269→          tasks: state.tasks.map((task) => {
  1270→            const shift = shifts.find(s => s.taskId === task.id);
  1271→            if (!shift) return task;
  1272→
  1273→            return {
  1274→              ...task,
  1275→              startDate: shift.newStartDate,
  1276→              dueDate: shift.newDueDate,
  1277→            };
  1278→          }),
  1279→        }));
  1280→
  1281→        // Log activity for each shifted task
  1282→        shifts.forEach(shift => {
  1283→          get().logActivity(shift.taskId, {
  1284→            action: 'updated',
  1285→            field: 'dates',
  1286→            newValue: shift.reason,
  1287→          });
  1288→        });
  1289→
  1290→        log.info('Dependent shifts applied successfully');
  1291→      },
  1292→
  1293→      // ==================== PHASE 1.3: CRITICAL PATH ANALYSIS ====================
  1294→
  1295→      getCriticalPath: () => {
  1296→        const tasks = get().tasks;
  1297→        return calculateCriticalPath(tasks);
  1298→      },
  1299→
  1300→      getTaskSlack: (taskId) => {
  1301→        const tasks = get().tasks;
  1302→        const task = tasks.find(t => t.id === taskId);
  1303→        if (!task) return 0;
  1304→        return calculateSlack(task, tasks);
  1305→      },
  1306→
  1307→      // ==================== PHASE 1.4: BASELINE COMPARISON ====================
  1308→
  1309→      setBaseline: () => {
  1310→        const tasks = get().tasks;
