  1323→      },
  1324→
  1325→      // ==================== PHASE A: ARCHIVE ACTIONS ====================
  1326→
  1327→      archiveTask: (id) => {
  1328→        const task = get().tasks.find((t) => t.id === id);
  1329→        if (!task) return;
  1330→
  1331→        const archivedTask: Task = {
