  1343→          action: 'updated',
  1344→          field: 'archived',
  1345→          newValue: 'true',
  1346→        });
  1347→      },
  1348→
  1349→      restoreTask: (id) => {
  1350→        const archivedTask = get().archivedTasks?.find((t) => t.id === id);
  1351→        if (!archivedTask) return;
  1352→
  1353→        // Remove archivedAt field when restoring
  1354→        const { archivedAt, ...restoredTask } = archivedTask;
  1355→
  1356→        set((state) => ({
  1357→          archivedTasks: (state.archivedTasks || []).filter((t) => t.id !== id),
  1358→          tasks: [...state.tasks, restoredTask as Task],
  1359→        }));
  1360→
  1361→        // Log restore action
  1362→        get().logActivity(id, {
  1363→          action: 'updated',
  1364→          field: 'archived',
  1365→          oldValue: 'true',
  1366→          newValue: 'false',
  1367→        });
  1368→      },
  1369→
  1370→      deleteArchivedTask: (id) => {
  1371→        set((state) => ({
  1372→          archivedTasks: (state.archivedTasks || []).filter((t) => t.id !== id),
  1373→        }));
  1374→      },
  1375→
  1376→      getArchivedTasks: () => {
  1377→        return (get().archivedTasks || []).sort((a, b) => {
  1378→          // Sort by archive date (most recent first)
  1379→          const dateA = new Date(a.archivedAt || 0).getTime();
  1380→          const dateB = new Date(b.archivedAt || 0).getTime();
  1381→          return dateB - dateA;
  1382→        });
  1383→      },
  1384→
  1385→      autoArchiveCompletedTasks: () => {
  1386→        const now = new Date();
  1387→        const fourteenDaysAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);
  1388→
  1389→        const tasksToArchive = get().tasks.filter((task) => {
  1390→          // Only archive tasks in "done" status
  1391→          if (task.status !== 'done') return false;
  1392→
  1393→          // Check if task has been completed for > 14 days
  1394→          if (task.lastCompletedAt) {
  1395→            const completedDate = new Date(task.lastCompletedAt);
  1396→            return completedDate < fourteenDaysAgo;
  1397→          }
  1398→
  1399→          return false;
  1400→        });
  1401→
  1402→        // Archive each task
  1403→        tasksToArchive.forEach((task) => {
  1404→          get().archiveTask(task.id);
  1405→        });
  1406→
  1407→        if (tasksToArchive.length > 0) {
  1408→          log.info('Auto-archived completed tasks', { count: tasksToArchive.length });
  1409→        }
  1410→      },
  1411→
  1412→      // ==================== PHASE B: TIME TRACKING ====================
  1413→
  1414→      startTimer: (taskId) => {
  1415→        const now = new Date().toISOString();
  1416→
  1417→        set((state) => ({
  1418→          tasks: state.tasks.map((task) => {
  1419→            if (task.id === taskId) {
  1420→              return {
  1421→                ...task,
  1422→                timeTracking: {
  1423→                  estimated: task.timeTracking?.estimated,
  1424→                  actual: task.timeTracking?.actual || 0,
  1425→                  activeTimerStart: now,
  1426→                  timerHistory: task.timeTracking?.timerHistory || [],
  1427→                },
  1428→              };
  1429→            }
  1430→            return task;
  1431→          }),
  1432→        }));
  1433→
  1434→        // Log timer start
  1435→        get().logActivity(taskId, {
  1436→          action: 'updated',
  1437→          field: 'timer',
  1438→          newValue: 'started',
  1439→        });
  1440→      },
  1441→
  1442→      stopTimer: (taskId) => {
  1443→        const now = new Date().toISOString();
  1444→        const state = get();
  1445→        const task = state.tasks.find((t) => t.id === taskId);
  1446→
  1447→        if (!task || !task.timeTracking?.activeTimerStart) {
