  1641→          tasksImported: newTasks.length,
  1642→          tagsCreated: newTags,
  1643→          errors: [],
  1644→          warnings: [],
  1645→        };
  1646→      },
  1647→
  1648→      // ==================== UI PREFERENCES ====================
  1649→
  1650→      setVisibleColumns: (count) => {
