  1660→      },
  1661→    }),
  1662→    {
  1663→      name: 'kanban-tasks',
  1664→      storage: createJSONStorage(() => createSyncedStorage()),
  1665→      version: 2, // Increment for dependency migration
  1666→      migrate: (persistedState: any, version: number) => {
