        }

        const percentage = Math.min(
          100,
          Math.floor((current / nextAchievement.threshold) * 100)
        );

        return {
          current,
          next: nextAchievement.threshold,
          percentage,
        };
      },

      // Reset stats (for testing or user request)
      resetStats: () => {
        set({
          stats: {
            tasksCompleted: 0,
            notesCreated: 0,
            hoursTracked: 0,
            currentStreak: 0,
            longestStreak: 0,
            lastActivityDate: undefined,
          },
          unlockedAchievements: [],
        });
      },
    }),
