 */
export function formatTemperature(
  tempF: number,
  unit: TemperatureUnit,
  showUnit = true
): string {
  if (unit === 'celsius') {
    const tempC = Math.round((tempF - 32) * (5 / 9));
    return showUnit ? `${tempC}°C` : `${tempC}°`;
  }
  return showUnit ? `${tempF}°F` : `${tempF}°`;
}

